import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { 
  Search, 
  Filter, 
  Eye, 
  UserCheck, 
  Clock, 
  MapPin, 
  DollarSign,
  Calendar,
  Phone,
  Mail,
  FileText,
  Star,
  AlertCircle,
  CheckCircle,
  XCircle,
  Users,
  Wrench,
  ChevronDown,
  ChevronRight,
  RefreshCw
} from 'lucide-react';
import { api } from '../../services/api';
import toast from 'react-hot-toast';

const OrderManagement = () => {
  const [jobs, setJobs] = useState([]);
  const [vendors, setVendors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [showAssignModal, setShowAssignModal] = useState(false);
  const [selectedVendor, setSelectedVendor] = useState('');
  const [assignmentTimeSlot, setAssignmentTimeSlot] = useState({
    date: '',
    startTime: '09:00',
    endTime: '17:00'
  });

  // Filters
  const [filters, setFilters] = useState({
    status: '',
    category: '',
    priority: '',
    search: ''
  });

  const [pagination, setPagination] = useState({
    page: 1,
    pages: 1,
    total: 0,
    limit: 10
  });

  const statusColors = {
    PENDING: 'bg-yellow-100 text-yellow-800',
    ASSIGNED: 'bg-blue-100 text-blue-800',
    IN_DISCUSSION: 'bg-purple-100 text-purple-800',
    QUOTE_SENT: 'bg-indigo-100 text-indigo-800',
    QUOTE_ACCEPTED: 'bg-green-100 text-green-800',
    PAID: 'bg-emerald-100 text-emerald-800',
    IN_PROGRESS: 'bg-orange-100 text-orange-800',
    COMPLETED: 'bg-green-200 text-green-900',
    CANCELLED: 'bg-red-100 text-red-800',
    REJECTED: 'bg-gray-100 text-gray-800'
  };

  const priorityColors = {
    LOW: 'text-green-600',
    MEDIUM: 'text-yellow-600',
    HIGH: 'text-orange-600',
    EMERGENCY: 'text-red-600'
  };

  useEffect(() => {
    fetchJobs();
    fetchVendors();
  }, [filters, pagination.page]);

  const fetchJobs = async () => {
    try {
      setLoading(true);
      const queryParams = new URLSearchParams({
        page: pagination.page,
        limit: pagination.limit,
        ...(filters.status && { status: filters.status }),
        ...(filters.search && { search: filters.search })
      });

      const response = await api.get(`/jobs?${queryParams}`);
      setJobs(response.data.jobs);
      setPagination(prev => ({
        ...prev,
        pages: response.data.pagination.pages,
        total: response.data.pagination.total
      }));
    } catch (error) {
      console.error('Error fetching jobs:', error);
      toast.error('Failed to fetch orders');
    } finally {
      setLoading(false);
    }
  };

  const fetchVendors = async () => {
    try {
      const response = await api.get('/admin/vendors');
      setVendors(response.data.vendors || []);
    } catch (error) {
      console.error('Error fetching vendors:', error);
    }
  };

  const handleAssignJob = async () => {
    if (!selectedVendor || !selectedJob) {
      toast.error('Please select a vendor');
      return;
    }

    try {
      const assignmentData = {
        vendorId: selectedVendor,
        assignedTimeSlot: assignmentTimeSlot
      };

      await api.patch(`/jobs/${selectedJob._id}/assign`, assignmentData);

      toast.success('Job assigned successfully! 🎉');
      setShowAssignModal(false);
      setSelectedJob(null);
      setSelectedVendor('');
      fetchJobs(); // Refresh the list

    } catch (error) {
      console.error('Error assigning job:', error);
      toast.error(error.response?.data?.message || 'Failed to assign job');
    }
  };

  const getVendorsForJob = (job) => {
    // Filter vendors by category and location
    return vendors.filter(vendor => {
      // Check if vendor handles this service category
      const hasCategory = vendor.serviceCategories?.includes(job.category);

      // Check if vendor serves this location (simplified)
      const servesLocation = true; // You can implement location-based filtering

      // Check if vendor is active and verified
      const isActiveAndVerified = vendor.isActive && vendor.verificationStatus === 'VERIFIED';

      return hasCategory && servesLocation && isActiveAndVerified;
    });
  };

  const getRatingStars = (rating) => {
    const stars = [];
    const roundedRating = Math.round(rating * 2) / 2; // Round to nearest 0.5

    for (let i = 1; i <= 5; i++) {
      if (i <= roundedRating) {
        stars.push(<Star key={i} className="w-4 h-4 fill-current text-yellow-400" />);
      } else if (i - 0.5 <= roundedRating) {
        stars.push(<Star key={i} className="w-4 h-4 fill-current text-yellow-400 opacity-50" />);
      } else {
        stars.push(<Star key={i} className="w-4 h-4 text-gray-300" />);
      }
    }
    return stars;
  };

  const JobDetailsModal = ({ job, onClose }) => (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg p-6 w-full max-w-4xl max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-900">Order Details</h2>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600"
          >
            <XCircle className="w-6 h-6" />
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Job Information */}
          <div className="space-y-4">
            <div className="bg-gray-50 rounded-lg p-4">
              <h3 className="text-lg font-semibold mb-3">Job Information</h3>
              <div className="space-y-2 text-sm">
                <div><strong>Job ID:</strong> {job.jobNumber}</div>
                <div><strong>Title:</strong> {job.title}</div>
                <div><strong>Category:</strong> {job.category}</div>
                <div className="flex items-center">
                  <strong className="mr-2">Priority:</strong>
                  <span className={`font-medium ${priorityColors[job.priority]}`}>
                    {job.priority}
                  </span>
                  {job.isEmergency && (
                    <span className="ml-2 px-2 py-1 bg-red-100 text-red-800 text-xs rounded-full">
                      EMERGENCY
                    </span>
                  )}
                </div>
                <div className="flex items-center">
                  <strong className="mr-2">Status:</strong>
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${statusColors[job.status]}`}>
                    {job.status.replace('_', ' ')}
                  </span>
                </div>
                <div><strong>Description:</strong> {job.description}</div>
                {job.specialInstructions && (
                  <div><strong>Special Instructions:</strong> {job.specialInstructions}</div>
                )}
              </div>
            </div>

            {/* Customer Information */}
            <div className="bg-gray-50 rounded-lg p-4">
              <h3 className="text-lg font-semibold mb-3">Customer Information</h3>
              <div className="space-y-2 text-sm">
                <div><strong>Name:</strong> {job.customerId?.firstName} {job.customerId?.lastName}</div>
                <div className="flex items-center">
                  <Mail className="w-4 h-4 mr-2 text-gray-400" />
                  {job.customerId?.email}
                </div>
                <div className="flex items-center">
                  <Phone className="w-4 h-4 mr-2 text-gray-400" />
                  {job.customerContactNumber || job.customerId?.phone}
                </div>
              </div>
            </div>

            {/* Timing */}
            <div className="bg-gray-50 rounded-lg p-4">
              <h3 className="text-lg font-semibold mb-3">Timing</h3>
              <div className="space-y-2 text-sm">
                <div className="flex items-center">
                  <Calendar className="w-4 h-4 mr-2 text-gray-400" />
                  <strong>Requested Date:</strong> {new Date(job.requestedTimeSlot?.date).toLocaleDateString()}
                </div>
                <div className="flex items-center">
                  <Clock className="w-4 h-4 mr-2 text-gray-400" />
                  <strong>Time:</strong> {job.requestedTimeSlot?.startTime} - {job.requestedTimeSlot?.endTime}
                </div>
                <div><strong>Estimated Duration:</strong> {job.estimatedDuration} hours</div>
              </div>
            </div>
          </div>

          {/* Location & Budget */}
          <div className="space-y-4">
            <div className="bg-gray-50 rounded-lg p-4">
              <h3 className="text-lg font-semibold mb-3">Location</h3>
              <div className="space-y-2 text-sm">
                <div className="flex items-start">
                  <MapPin className="w-4 h-4 mr-2 text-gray-400 mt-1" />
                  <div>
                    <div>{job.location?.address}</div>
                    <div>{job.location?.city}, {job.location?.state} {job.location?.zipCode}</div>
                  </div>
                </div>
                {job.accessInstructions && (
                  <div><strong>Access Instructions:</strong> {job.accessInstructions}</div>
                )}
              </div>
            </div>

            <div className="bg-gray-50 rounded-lg p-4">
              <h3 className="text-lg font-semibold mb-3">Budget & Pricing</h3>
              <div className="space-y-2 text-sm">
                <div className="flex items-center">
                  <DollarSign className="w-4 h-4 mr-2 text-gray-400" />
                  <strong>Customer Budget:</strong> ${job.estimatedBudget?.toFixed(2)}
                </div>
                {job.vendorQuote?.amount && (
                  <>
                    <div><strong>Vendor Quote:</strong> ${job.vendorQuote.amount.toFixed(2)}</div>
                    {job.vendorQuote.description && (
                      <div><strong>Quote Description:</strong> {job.vendorQuote.description}</div>
                    )}
                  </>
                )}
                {job.totalAmount && (
                  <>
                    <div><strong>Final Amount:</strong> ${job.totalAmount.toFixed(2)}</div>
                    <div><strong>Platform Commission (10%):</strong> ${job.commission?.platformAmount?.toFixed(2)}</div>
                    <div><strong>Vendor Amount (90%):</strong> ${job.commission?.vendorAmount?.toFixed(2)}</div>
                  </>
                )}
              </div>
            </div>

            {/* Vendor Information (if assigned) */}
            {job.vendorId && (
              <div className="bg-gray-50 rounded-lg p-4">
                <h3 className="text-lg font-semibold mb-3">Assigned Vendor</h3>
                <div className="space-y-2 text-sm">
                  <div><strong>Name:</strong> {job.vendorId?.firstName} {job.vendorId?.lastName}</div>
                  <div className="flex items-center">
                    <Mail className="w-4 h-4 mr-2 text-gray-400" />
                    {job.vendorId?.email}
                  </div>
                  <div className="flex items-center">
                    <Phone className="w-4 h-4 mr-2 text-gray-400" />
                    {job.vendorId?.phone}
                  </div>
                  {job.vendorDetails?.companyName && (
                    <div><strong>Company:</strong> {job.vendorDetails.companyName}</div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Status History */}
        {job.statusHistory && job.statusHistory.length > 0 && (
          <div className="mt-6">
            <h3 className="text-lg font-semibold mb-3">Status History</h3>
            <div className="space-y-2">
              {job.statusHistory.slice().reverse().map((history, index) => (
                <div key={index} className="flex items-center space-x-3 text-sm">
                  <div className="w-2 h-2 bg-gray-400 rounded-full"></div>
                  <div><strong>{history.status.replace('_', ' ')}:</strong></div>
                  <div>{new Date(history.timestamp).toLocaleString()}</div>
                  {history.notes && <div>- {history.notes}</div>}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Actions */}
        <div className="mt-6 flex justify-end space-x-4">
          {job.status === 'PENDING' && (
            <button
              onClick={() => {
                setSelectedJob(job);
                setShowAssignModal(true);
                onClose();
              }}
              className="px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700"
            >
              Assign to Vendor
            </button>
          )}
          <button
            onClick={onClose}
            className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );

  const AssignmentModal = () => {
    const availableVendors = getVendorsForJob(selectedJob);

    return (
      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
        <div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-gray-900">Assign Vendor</h2>
            <button
              onClick={() => setShowAssignModal(false)}
              className="text-gray-400 hover:text-gray-600"
            >
              <XCircle className="w-6 h-6" />
            </button>
          </div>

          <div className="mb-6">
            <h3 className="text-lg font-semibold mb-2">Job: {selectedJob?.title}</h3>
            <div className="text-sm text-gray-600">
              <div>Category: {selectedJob?.category}</div>
              <div>Location: {selectedJob?.location?.city}</div>
              <div>Budget: ${selectedJob?.estimatedBudget?.toFixed(2)}</div>
            </div>
          </div>

          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Select Vendor *
            </label>
            {availableVendors.length > 0 ? (
              <div className="space-y-3 max-h-60 overflow-y-auto">
                {availableVendors.map((vendor) => (
                  <label
                    key={vendor._id}
                    className={`flex items-center p-4 border rounded-lg cursor-pointer hover:bg-gray-50 ${
                      selectedVendor === vendor.userId._id ? 'border-orange-500 bg-orange-50' : 'border-gray-300'
                    }`}
                  >
                    <input
                      type="radio"
                      name="vendor"
                      value={vendor.userId._id}
                      checked={selectedVendor === vendor.userId._id}
                      onChange={(e) => setSelectedVendor(e.target.value)}
                      className="mr-3 text-orange-600"
                    />
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <div>
                          <div className="font-medium">
                            {vendor.userId.firstName} {vendor.userId.lastName}
                          </div>
                          {vendor.companyName && (
                            <div className="text-sm text-gray-600">{vendor.companyName}</div>
                          )}
                        </div>
                        <div className="text-right">
                          <div className="flex items-center">
                            {getRatingStars(vendor.averageRating || 4.5)}
                            <span className="ml-1 text-sm text-gray-600">
                              ({vendor.averageRating?.toFixed(1) || '4.5'})
                            </span>
                          </div>
                          <div className="text-sm text-gray-500">
                            {vendor.totalJobsCompleted || 0} jobs completed
                          </div>
                        </div>
                      </div>
                      <div className="mt-2 text-sm text-gray-600">
                        <div>Categories: {vendor.serviceCategories?.join(', ')}</div>
                        <div>Service Area: {vendor.serviceArea}</div>
                      </div>
                    </div>
                  </label>
                ))}
              </div>
            ) : (
              <div className="text-center py-8 text-gray-500">
                <Users className="w-12 h-12 mx-auto mb-4 text-gray-300" />
                <p>No available vendors found for this job category and location.</p>
              </div>
            )}
          </div>

          {/* Assignment Time Slot */}
          <div className="mb-6">
            <h3 className="text-lg font-semibold mb-3">Assignment Schedule</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
                <input
                  type="date"
                  value={assignmentTimeSlot.date}
                  onChange={(e) => setAssignmentTimeSlot(prev => ({ ...prev, date: e.target.value }))}
                  min={new Date().toISOString().split('T')[0]}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Start Time</label>
                <input
                  type="time"
                  value={assignmentTimeSlot.startTime}
                  onChange={(e) => setAssignmentTimeSlot(prev => ({ ...prev, startTime: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">End Time</label>
                <input
                  type="time"
                  value={assignmentTimeSlot.endTime}
                  onChange={(e) => setAssignmentTimeSlot(prev => ({ ...prev, endTime: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500"
                />
              </div>
            </div>
          </div>

          <div className="flex justify-end space-x-4">
            <button
              onClick={() => setShowAssignModal(false)}
              className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
            >
              Cancel
            </button>
            <button
              onClick={handleAssignJob}
              disabled={!selectedVendor || !assignmentTimeSlot.date}
              className="px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Assign Job
            </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="p-6">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Order Management</h1>
          <p className="text-gray-600">Review and assign customer orders to vendors</p>
        </div>
        <button
          onClick={fetchJobs}
          className="flex items-center px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700"
        >
          <RefreshCw className="w-4 h-4 mr-2" />
          Refresh
        </button>
      </div>

      {/* Filters */}
      <div className="mb-6 bg-white rounded-lg shadow-sm p-4">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {/* Search */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Search</label>
            <div className="relative">
              <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
              <input
                type="text"
                value={filters.search}
                onChange={(e) => setFilters(prev => ({ ...prev, search: e.target.value }))}
                placeholder="Job title, customer name..."
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500"
              />
            </div>
          </div>

          {/* Status Filter */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <select
              value={filters.status}
              onChange={(e) => setFilters(prev => ({ ...prev, status: e.target.value }))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500"
            >
              <option value="">All Statuses</option>
              <option value="PENDING">Pending</option>
              <option value="ASSIGNED">Assigned</option>
              <option value="IN_DISCUSSION">In Discussion</option>
              <option value="QUOTE_SENT">Quote Sent</option>
              <option value="QUOTE_ACCEPTED">Quote Accepted</option>
              <option value="PAID">Paid</option>
              <option value="IN_PROGRESS">In Progress</option>
              <option value="COMPLETED">Completed</option>
            </select>
          </div>

          {/* Priority Filter */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Priority</label>
            <select
              value={filters.priority}
              onChange={(e) => setFilters(prev => ({ ...prev, priority: e.target.value }))}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-orange-500 focus:border-orange-500"
            >
              <option value="">All Priorities</option>
              <option value="EMERGENCY">Emergency</option>
              <option value="HIGH">High</option>
              <option value="MEDIUM">Medium</option>
              <option value="LOW">Low</option>
            </select>
          </div>

          {/* Clear Filters */}
          <div className="flex items-end">
            <button
              onClick={() => setFilters({ status: '', category: '', priority: '', search: '' })}
              className="w-full px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
            >
              Clear Filters
            </button>
          </div>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-6">
        <div className="bg-white rounded-lg shadow-sm p-6">
          <div className="flex items-center">
            <div className="p-3 rounded-full bg-yellow-100">
              <Clock className="w-6 h-6 text-yellow-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-600">Pending Orders</p>
              <p className="text-2xl font-bold text-gray-900">
                {jobs.filter(job => job.status === 'PENDING').length}
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-sm p-6">
          <div className="flex items-center">
            <div className="p-3 rounded-full bg-blue-100">
              <UserCheck className="w-6 h-6 text-blue-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-600">Assigned</p>
              <p className="text-2xl font-bold text-gray-900">
                {jobs.filter(job => ['ASSIGNED', 'IN_DISCUSSION', 'QUOTE_SENT'].includes(job.status)).length}
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-sm p-6">
          <div className="flex items-center">
            <div className="p-3 rounded-full bg-orange-100">
              <Wrench className="w-6 h-6 text-orange-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-600">In Progress</p>
              <p className="text-2xl font-bold text-gray-900">
                {jobs.filter(job => ['PAID', 'IN_PROGRESS'].includes(job.status)).length}
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-sm p-6">
          <div className="flex items-center">
            <div className="p-3 rounded-full bg-green-100">
              <CheckCircle className="w-6 h-6 text-green-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-600">Completed</p>
              <p className="text-2xl font-bold text-gray-900">
                {jobs.filter(job => job.status === 'COMPLETED').length}
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Orders Table */}
      <div className="bg-white rounded-lg shadow-sm overflow-hidden">
        <div className="px-6 py-4 border-b border-gray-200">
          <h2 className="text-lg font-semibold text-gray-900">All Orders</h2>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-12">
            <RefreshCw className="w-8 h-8 animate-spin text-orange-600" />
            <span className="ml-2 text-gray-600">Loading orders...</span>
          </div>
        ) : jobs.length === 0 ? (
          <div className="text-center py-12">
            <FileText className="w-12 h-12 mx-auto text-gray-400 mb-4" />
            <p className="text-gray-500">No orders found</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Order Details
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Customer
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Location
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Budget
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {jobs.map((job) => (
                  <tr key={job._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div>
                        <div className="text-sm font-medium text-gray-900">{job.title}</div>
                        <div className="text-sm text-gray-500">
                          {job.jobNumber} • {job.category}
                        </div>
                        <div className="flex items-center mt-1">
                          <span className={`text-xs font-medium ${priorityColors[job.priority]}`}>
                            {job.priority}
                          </span>
                          {job.isEmergency && (
                            <span className="ml-2 px-2 py-1 bg-red-100 text-red-800 text-xs rounded-full">
                              EMERGENCY
                            </span>
                          )}
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div>
                        <div className="text-sm font-medium text-gray-900">
                          {job.customerId?.firstName} {job.customerId?.lastName}
                        </div>
                        <div className="text-sm text-gray-500">{job.customerId?.email}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-900">{job.location?.city}</div>
                      <div className="text-sm text-gray-500">{job.location?.state}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900">
                        ${job.estimatedBudget?.toFixed(2)}
                      </div>
                      {job.vendorQuote?.amount && (
                        <div className="text-sm text-gray-500">
                          Quote: ${job.vendorQuote.amount.toFixed(2)}
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full ${statusColors[job.status]}`}>
                        {job.status.replace('_', ' ')}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex space-x-2">
                        <button
                          onClick={() => setSelectedJob(job)}
                          className="text-blue-600 hover:text-blue-900"
                        >
                          <Eye className="w-4 h-4" />
                        </button>
                        {job.status === 'PENDING' && (
                          <button
                            onClick={() => {
                              setSelectedJob(job);
                              setShowAssignModal(true);
                            }}
                            className="text-orange-600 hover:text-orange-900"
                          >
                            <UserCheck className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Pagination */}
        {pagination.pages > 1 && (
          <div className="px-6 py-4 border-t border-gray-200">
            <div className="flex items-center justify-between">
              <div className="text-sm text-gray-700">
                Showing page {pagination.page} of {pagination.pages} ({pagination.total} total orders)
              </div>
              <div className="flex space-x-2">
                <button
                  onClick={() => setPagination(prev => ({ ...prev, page: Math.max(1, prev.page - 1) }))}
                  disabled={pagination.page === 1}
                  className="px-3 py-1 border border-gray-300 text-gray-700 rounded hover:bg-gray-50 disabled:opacity-50"
                >
                  Previous
                </button>
                <button
                  onClick={() => setPagination(prev => ({ ...prev, page: Math.min(prev.pages, prev.page + 1) }))}
                  disabled={pagination.page === pagination.pages}
                  className="px-3 py-1 border border-gray-300 text-gray-700 rounded hover:bg-gray-50 disabled:opacity-50"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      {selectedJob && !showAssignModal && (
        <JobDetailsModal 
          job={selectedJob} 
          onClose={() => setSelectedJob(null)} 
        />
      )}

      {showAssignModal && selectedJob && (
        <AssignmentModal />
      )}
    </div>
  );
};

export default OrderManagement;
